import{ROOT_WORKSPACE_NAME}from"../constants.js";import{join}from"./path.js";export const createWorkspaceFilePathFilter=(t,r,n)=>{if(!r||!n)return()=>!0;const e=r.has(ROOT_WORKSPACE_NAME),s=n.filter(t=>t!==ROOT_WORKSPACE_NAME).map(r=>({name:r,dir:join(t,r)})).sort((t,r)=>r.name.split("/").length-t.name.split("/").length);return t=>{const n=s.find(r=>t.startsWith(`${r.dir}/`));return n?r.has(n.name):e}};